/* livery-lens web — pure pipeline math, a direct port of extract.py.
 *
 * No DOM, no dependencies: this module runs in the browser and under Node
 * (docs/tests/run-tests.mjs exercises it against fixtures generated by the
 * Python CLI).
 *
 * Differences vs the Python CLI, by design:
 *  - LAB conversion is float CIELAB (D65). OpenCV's 8-bit LAB is quantized
 *    (L in 100/255 steps, integer a/b); resulting palettes agree to well
 *    under 1 dE.
 *  - k-means uses its own seeded PRNG (mulberry32), so cluster *iteration*
 *    order can differ from sklearn, but merged palettes converge to the
 *    same colors. Determinism within JS is guaranteed by the fixed seed.
 */

export const MAX_DIM = 1200;          // working resolution (long edge)
export const SAMPLE_PIXELS = 60000;   // max pixels fed to k-means
export const MERGE_DELTA_E = 14.0;    // CIE76 distance below which clusters merge
export const DARK_V_CUTOFF = 32;      // HSV value below => tires/glass/shadow
export const MIN_ZONE_FRAC = 0.005;   // ignore zones smaller than this frac of car

// ------------------------------------------------------------ color space

// sRGB (0-255) -> CIELAB (D65, 2 degree observer)
export function srgbToLab(r, g, b) {
  const f = (u) => {
    u /= 255;
    return u <= 0.04045 ? u / 12.92 : Math.pow((u + 0.055) / 1.055, 2.4);
  };
  const rl = f(r), gl = f(g), bl = f(b);
  // sRGB D65 matrix
  const x = (0.4124564 * rl + 0.3575761 * gl + 0.1804375 * bl) / 0.95047;
  const y = (0.2126729 * rl + 0.7151522 * gl + 0.0721750 * bl);
  const z = (0.0193339 * rl + 0.1191920 * gl + 0.9503041 * bl) / 1.08883;
  const g3 = (t) => t > 0.008856 ? Math.cbrt(t) : (7.787 * t + 16 / 116);
  const fx = g3(x), fy = g3(y), fz = g3(z);
  return [116 * fy - 16, 500 * (fx - fy), 200 * (fy - fz)];
}

// CIELAB -> sRGB (0-255, clamped)
export function labToSrgb(L, a, b) {
  const fy = (L + 16) / 116;
  const fx = fy + a / 500;
  const fz = fy - b / 200;
  const inv = (t) => {
    const t3 = t * t * t;
    return t3 > 0.008856 ? t3 : (t - 16 / 116) / 7.787;
  };
  const x = inv(fx) * 0.95047, y = inv(fy), z = inv(fz) * 1.08883;
  const rl =  3.2404542 * x - 1.5371385 * y - 0.4985314 * z;
  const gl = -0.9692660 * x + 1.8760108 * y + 0.0415560 * z;
  const bl =  0.0556434 * x - 0.2040259 * y + 1.0572252 * z;
  const enc = (u) => {
    u = u <= 0.0031308 ? 12.92 * u : 1.055 * Math.pow(u, 1 / 2.4) - 0.055;
    return Math.min(255, Math.max(0, Math.round(u * 255)));
  };
  return [enc(rl), enc(gl), enc(bl)];
}

export function deltaE76(l1, l2) {
  const d0 = l1[0] - l2[0], d1 = l1[1] - l2[1], d2 = l1[2] - l2[2];
  return Math.sqrt(d0 * d0 + d1 * d1 + d2 * d2);
}

export function hexOfRgb(r, g, b) {
  return "#" + [r, g, b].map((v) => v.toString(16).padStart(2, "0")).join("");
}

// HSV saturation of an sRGB color, 0..1 (matches cv2: (max-min)/max)
export function saturationOfRgb(r, g, b) {
  const mx = Math.max(r, g, b);
  if (mx === 0) return 0;
  return (mx - Math.min(r, g, b)) / mx;
}

// -------------------------------------------------------------------- rng

// mulberry32 — small deterministic PRNG for reproducible sampling/k-means
export function mulberry32(seed) {
  let s = seed >>> 0;
  return function () {
    s = (s + 0x6d2b79f5) >>> 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// ---------------------------------------------------------------- k-means

// points: Float64Array of n*3 (LAB). Returns {centers: Float64Array k*3,
// inertia}. k-means++ init, Lloyd iterations, best of nInit restarts.
// Deterministic for a given seed.
export function kmeans(points, n, k, { seed = 42, nInit = 4, maxIter = 100 } = {}) {
  const rng = mulberry32(seed);
  let best = null;

  const dist2 = (i, cx, cy, cz) => {
    const dx = points[i * 3] - cx, dy = points[i * 3 + 1] - cy, dz = points[i * 3 + 2] - cz;
    return dx * dx + dy * dy + dz * dz;
  };

  for (let run = 0; run < nInit; run++) {
    // --- k-means++ init
    const centers = new Float64Array(k * 3);
    const d2 = new Float64Array(n).fill(Infinity);
    let first = Math.floor(rng() * n);
    centers[0] = points[first * 3];
    centers[1] = points[first * 3 + 1];
    centers[2] = points[first * 3 + 2];
    for (let c = 1; c < k; c++) {
      let sum = 0;
      const pcx = centers[(c - 1) * 3], pcy = centers[(c - 1) * 3 + 1], pcz = centers[(c - 1) * 3 + 2];
      for (let i = 0; i < n; i++) {
        const d = dist2(i, pcx, pcy, pcz);
        if (d < d2[i]) d2[i] = d;
        sum += d2[i];
      }
      let target = rng() * sum, idx = n - 1;
      for (let i = 0; i < n; i++) {
        target -= d2[i];
        if (target <= 0) { idx = i; break; }
      }
      centers[c * 3] = points[idx * 3];
      centers[c * 3 + 1] = points[idx * 3 + 1];
      centers[c * 3 + 2] = points[idx * 3 + 2];
    }

    // --- Lloyd iterations
    const labels = new Int32Array(n);
    const counts = new Int32Array(k);
    const sums = new Float64Array(k * 3);
    let inertia = 0;
    for (let iter = 0; iter < maxIter; iter++) {
      counts.fill(0); sums.fill(0); inertia = 0;
      for (let i = 0; i < n; i++) {
        let bd = Infinity, bj = 0;
        for (let j = 0; j < k; j++) {
          const d = dist2(i, centers[j * 3], centers[j * 3 + 1], centers[j * 3 + 2]);
          if (d < bd) { bd = d; bj = j; }
        }
        labels[i] = bj; counts[bj]++;
        sums[bj * 3] += points[i * 3];
        sums[bj * 3 + 1] += points[i * 3 + 1];
        sums[bj * 3 + 2] += points[i * 3 + 2];
        inertia += bd;
      }
      // empty clusters: seize the point farthest from its center
      for (let j = 0; j < k; j++) {
        if (counts[j] > 0) continue;
        let far = 0, farD = -1;
        for (let i = 0; i < n; i++) {
          const c = labels[i];
          const d = dist2(i, centers[c * 3], centers[c * 3 + 1], centers[c * 3 + 2]);
          if (d > farD) { farD = d; far = i; }
        }
        const old = labels[far];
        counts[old]--; counts[j] = 1;
        sums[old * 3] -= points[far * 3];
        sums[old * 3 + 1] -= points[far * 3 + 1];
        sums[old * 3 + 2] -= points[far * 3 + 2];
        sums[j * 3] = points[far * 3];
        sums[j * 3 + 1] = points[far * 3 + 1];
        sums[j * 3 + 2] = points[far * 3 + 2];
        labels[far] = j;
      }
      let shift = 0;
      for (let j = 0; j < k; j++) {
        const cnt = counts[j] || 1;
        const nx = sums[j * 3] / cnt, ny = sums[j * 3 + 1] / cnt, nz = sums[j * 3 + 2] / cnt;
        const dx = nx - centers[j * 3], dy = ny - centers[j * 3 + 1], dz = nz - centers[j * 3 + 2];
        shift += dx * dx + dy * dy + dz * dz;
        centers[j * 3] = nx; centers[j * 3 + 1] = ny; centers[j * 3 + 2] = nz;
      }
      if (shift < 1e-8) break;
    }
    if (!best || inertia < best.inertia) best = { centers: centers.slice(), inertia };
  }
  return best;
}

// ---------------------------------------------------------------- palette

/**
 * Port of extract.py extract_palette().
 * rgba: Uint8ClampedArray (RGBA), mask: Uint8Array (0/255) or null,
 * Returns {clusters, labelMap (Int32Array, -1 outside livery), liveryCount}.
 */
export function extractPalette(rgba, width, height, mask, nColors, seed = 42) {
  const npx = width * height;

  // livery mask: inside car mask AND not near-black (HSV V >= cutoff)
  let livery = new Uint8Array(npx);
  let liveryCount = 0;
  for (let i = 0; i < npx; i++) {
    if (mask && !mask[i]) continue;
    const r = rgba[i * 4], g = rgba[i * 4 + 1], b = rgba[i * 4 + 2];
    if (Math.max(r, g, b) >= DARK_V_CUTOFF) { livery[i] = 1; liveryCount++; }
  }
  if (liveryCount < 500) { // dark car — keep everything inside the mask
    livery = new Uint8Array(npx);
    liveryCount = 0;
    for (let i = 0; i < npx; i++) {
      if (!mask || mask[i]) { livery[i] = 1; liveryCount++; }
    }
  }

  // LAB points for every livery pixel
  const pts = new Float64Array(liveryCount * 3);
  const ptIndex = new Int32Array(liveryCount); // pixel index per point
  let p = 0;
  for (let i = 0; i < npx; i++) {
    if (!livery[i]) continue;
    const lab = srgbToLab(rgba[i * 4], rgba[i * 4 + 1], rgba[i * 4 + 2]);
    pts[p * 3] = lab[0]; pts[p * 3 + 1] = lab[1]; pts[p * 3 + 2] = lab[2];
    ptIndex[p] = i;
    p++;
  }

  // sample for fitting
  let sample = pts, nSample = liveryCount;
  if (liveryCount > SAMPLE_PIXELS) {
    const rng = mulberry32(seed);
    sample = new Float64Array(SAMPLE_PIXELS * 3);
    // partial Fisher-Yates over indices
    const idx = new Int32Array(liveryCount);
    for (let i = 0; i < liveryCount; i++) idx[i] = i;
    for (let i = 0; i < SAMPLE_PIXELS; i++) {
      const j = i + Math.floor(rng() * (liveryCount - i));
      const t = idx[i]; idx[i] = idx[j]; idx[j] = t;
      sample[i * 3] = pts[idx[i] * 3];
      sample[i * 3 + 1] = pts[idx[i] * 3 + 1];
      sample[i * 3 + 2] = pts[idx[i] * 3 + 2];
    }
    nSample = SAMPLE_PIXELS;
  }

  const k = Math.min(nColors, Math.max(2, Math.floor(nSample / 200)));
  const { centers } = kmeans(sample, nSample, k, { seed });

  // merge perceptually-close clusters (CIE76), original index order
  const merged = []; // arrays of original center indices
  for (let i = 0; i < k; i++) {
    let joined = false;
    for (const group of merged) {
      const g0 = group[0];
      const d = deltaE76(
        [centers[i * 3], centers[i * 3 + 1], centers[i * 3 + 2]],
        [centers[g0 * 3], centers[g0 * 3 + 1], centers[g0 * 3 + 2]]);
      if (d < MERGE_DELTA_E) { group.push(i); joined = true; break; }
    }
    if (!joined) merged.push([i]);
  }
  const remap = new Int32Array(k);
  merged.forEach((group, gi) => group.forEach((orig) => { remap[orig] = gi; }));

  // assign every livery pixel to nearest ORIGINAL center, then remap
  const nGroups = merged.length;
  const labelMap = new Int32Array(npx).fill(-1);
  const groupCount = new Int32Array(nGroups);
  const groupSum = new Float64Array(nGroups * 3);
  for (let i = 0; i < liveryCount; i++) {
    const x = pts[i * 3], y = pts[i * 3 + 1], z = pts[i * 3 + 2];
    let bd = Infinity, bj = 0;
    for (let j = 0; j < k; j++) {
      const dx = x - centers[j * 3], dy = y - centers[j * 3 + 1], dz = z - centers[j * 3 + 2];
      const d = dx * dx + dy * dy + dz * dz;
      if (d < bd) { bd = d; bj = j; }
    }
    const gi = remap[bj];
    labelMap[ptIndex[i]] = gi;
    groupCount[gi]++;
    groupSum[gi * 3] += x; groupSum[gi * 3 + 1] += y; groupSum[gi * 3 + 2] += z;
  }

  const clusters = [];
  for (let gi = 0; gi < nGroups; gi++) {
    const cnt = groupCount[gi];
    // A merged group can end up with zero pixels when a stray k-means center
    // loses every assignment tie-break; sklearn collapses duplicate centers
    // so the CLI never emits these in practice. Drop them for parity.
    if (cnt === 0) continue;
    const L = groupSum[gi * 3] / cnt,
          A = groupSum[gi * 3 + 1] / cnt,
          B = groupSum[gi * 3 + 2] / cnt;
    const [r, g, b] = labToSrgb(L, A, B);
    clusters.push({
      gi,
      lab: [Math.round(L * 100) / 100, Math.round(A * 100) / 100, Math.round(B * 100) / 100],
      rgb: [r, g, b],
      hex: hexOfRgb(r, g, b),
      coverage: cnt / liveryCount,
      saturation: Math.round(saturationOfRgb(r, g, b) * 1000) / 1000,
    });
  }
  clusters.sort((a, b) => b.coverage - a.coverage);
  return { clusters, labelMap, liveryCount };
}

// role heuristic — identical to extract.py assign_roles()
export function assignRoles(clusters) {
  clusters.forEach((c, i) => {
    if (i === 0) c.role = "base";
    else if (c.coverage >= 0.15 || (c.saturation > 0.45 && c.coverage >= 0.025)) c.role = "accent";
    else c.role = "detail";
  });
  return clusters;
}

// ------------------------------------------------------------------ zones

// 7x7 median filter on the label map (labels+1, so -1 -> 0), like
// cv2.medianBlur(labels+1, 7). Replicated borders; counting median since
// labels are small ints.
export function medianFilterLabels(labelMap, width, height, ksize = 7) {
  const r = ksize >> 1;
  const out = new Int32Array(labelMap.length);
  let maxL = 0;
  for (let i = 0; i < labelMap.length; i++) if (labelMap[i] > maxL) maxL = labelMap[i];
  const hist = new Int32Array(maxL + 2);
  const half = (ksize * ksize) >> 1; // median position (0-based): 24 for 7x7
  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      hist.fill(0);
      for (let dy = -r; dy <= r; dy++) {
        const yy = Math.min(height - 1, Math.max(0, y + dy));
        for (let dx = -r; dx <= r; dx++) {
          const xx = Math.min(width - 1, Math.max(0, x + dx));
          hist[labelMap[yy * width + xx] + 1]++;
        }
      }
      let acc = 0, med = 0;
      for (let v = 0; v < hist.length; v++) {
        acc += hist[v];
        if (acc > half) { med = v; break; }
      }
      out[y * width + x] = med - 1;
    }
  }
  return out;
}

// connected components (8-connectivity) on a binary Uint8Array
export function connectedComponents(bin, width, height) {
  const labels = new Int32Array(width * height).fill(-1);
  const comps = []; // {area, minX, minY, maxX, maxY, sumX, sumY}
  const stack = new Int32Array(width * height);
  for (let i = 0; i < width * height; i++) {
    if (!bin[i] || labels[i] >= 0) continue;
    const id = comps.length;
    const c = { area: 0, minX: width, minY: height, maxX: -1, maxY: -1, sumX: 0, sumY: 0 };
    let sp = 0;
    stack[sp++] = i; labels[i] = id;
    while (sp > 0) {
      const cur = stack[--sp];
      const cy = (cur / width) | 0, cx = cur - cy * width;
      c.area++;
      c.sumX += cx; c.sumY += cy;
      if (cx < c.minX) c.minX = cx;
      if (cy < c.minY) c.minY = cy;
      if (cx > c.maxX) c.maxX = cx;
      if (cy > c.maxY) c.maxY = cy;
      for (let dy = -1; dy <= 1; dy++) {
        const ny = cy + dy;
        if (ny < 0 || ny >= height) continue;
        for (let dx = -1; dx <= 1; dx++) {
          const nx = cx + dx;
          if (nx < 0 || nx >= width) continue;
          const ni = ny * width + nx;
          if (bin[ni] && labels[ni] < 0) { labels[ni] = id; stack[sp++] = ni; }
        }
      }
    }
    comps.push(c);
  }
  return { labels, comps };
}

// per-color connected regions: bbox, centroid, area fraction (top 12)
export function zoneGeometry(cleanLabels, width, height, clusters, carArea) {
  const zones = [];
  const bin = new Uint8Array(width * height);
  for (const c of clusters) {
    bin.fill(0);
    for (let i = 0; i < bin.length; i++) if (cleanLabels[i] === c.gi) bin[i] = 1;
    const { comps } = connectedComponents(bin, width, height);
    const regions = [];
    for (const r of comps) {
      if (r.area < MIN_ZONE_FRAC * carArea) continue;
      regions.push({
        bbox: [r.minX, r.minY, r.maxX - r.minX + 1, r.maxY - r.minY + 1],
        centroid: [Math.round((r.sumX / r.area) * 10) / 10,
                   Math.round((r.sumY / r.area) * 10) / 10],
        area_frac_of_car: Math.round((r.area / carArea) * 10000) / 10000,
      });
    }
    regions.sort((a, b) => b.area_frac_of_car - a.area_frac_of_car);
    zones.push({
      hex: c.hex, role: c.role,
      coverage: Math.round(c.coverage * 10000) / 10000,
      regions: regions.slice(0, 12),
    });
  }
  return zones;
}

// ----------------------------------------------------------------- output

// identical schema to the Python CLI's palette.json
export function paletteJson(srcName, segmenter, clusters) {
  return {
    source: srcName,
    segmenter,
    colors: clusters.map((c) => ({
      hex: c.hex, role: c.role,
      coverage: Math.round(c.coverage * 1e12) / 1e12,
      saturation: c.saturation, lab: c.lab,
    })),
  };
}

// identical schema to the Python CLI's clearcoat_starter.json
export function clearcoatStarter(srcName, clusters, generator = "livery-lens web") {
  const base = clusters.find((c) => c.role === "base") || clusters[0];
  return {
    schema: "livery-lens/palette@1",
    source: {
      photo: srcName,
      generator,
      generated: new Date().toISOString().replace(/\.\d{3}Z$/, "+00:00"),
    },
    baseColor: base.hex,
    colors: clusters.map((c) => ({
      hex: c.hex, role: c.role,
      coverage: Math.round(c.coverage * 10000) / 10000,
      lab: c.lab,
    })),
    notes: "Coverage is the fraction of detected car-body pixels. " +
           "Roles are heuristic guesses (base/accent/detail).",
  };
}
